const update = $input.item.json;

let chatId, texto, callbackData, callbackQueryId;

// callback_query (clique em botão)
if (update.callback_query) {
  const cq = update.callback_query;
  chatId = String(cq.from?.id ?? cq.message?.chat?.id);
  callbackData = cq.data;
  callbackQueryId = String(cq.id);
}
// n8n às vezes desempacota o callback_query diretamente
else if (update.data && (update.from || update.message)) {
  chatId = String(update.from?.id ?? update.message?.chat?.id);
  callbackData = update.data;
  callbackQueryId = String(update.id);
}
// message normal
else if (update.message?.text) {
  chatId = String(update.message.from?.id ?? update.message.chat?.id);
  texto = update.message.text;
}
// n8n desempacota message diretamente
else if (update.text && update.from) {
  chatId = String(update.from.id);
  texto = update.text;
}
else {
  return [];
}

if (!chatId || chatId === 'undefined') return [];

return [{ json: { chatId, texto, callbackData, callbackQueryId } }];
